# Simulated auth tokens -> user ids
AUTH_TOKENS = {
    "token-alice": "1",
    "token-bob": "2",
    "token-charlie": "3",
}


# --- Authentication Middleware ---

class AuthenticationMiddleware(BaseHTTPMiddleware):
    """
    Middleware that extracts the Authorization header and sets
    `request.state.current_user` to the corresponding user dict (or None).
    
    Expected header format: "Bearer <token>"
    """

    async def dispatch(self, request: Request, call_next):
        current_user = None
        auth_header = request.headers.get("Authorization", "")

        if auth_header.startswith("Bearer "):
            token = auth_header[len("Bearer "):]
            user_id = AUTH_TOKENS.get(token)
            if user_id and user_id in USERS_DB:
                current_user = USERS_DB[user_id]

        request.state.current_user = current_user
        response = await call_next(request)
        return response


# --- Resolvers ---

query = QueryType()
user_type = ObjectType("User")
post_type = ObjectType("Post")


def get_current_user_from_context(info):
    """Helper to extract current_user from the GraphQL context."""
    request = info.context.get("request")
    if request and hasattr(request, "state") and hasattr(request.state, "current_user"):
        return request.state.current_user
    return None


# ----- Query Resolvers -----

@query.field("me")
def resolve_me(_, info):
    """Return the currently authenticated user, or None."""
    current_user = get_current_user_from_context(info)
    if current_user is None:
        return None
    return current_user


@query.field("user")
def resolve_user(_, info, id):
    """Fetch a single user by ID."""
    return USERS_DB.get(id)


@query.field("users")
def resolve_users(_, info):
    """Return all users."""
    return list(USERS_DB.values())


@query.field("post")
def resolve_post(_, info, id):
    """Fetch a single post by ID."""
    return POSTS_DB.get(id)


@query.field("posts")
def resolve_posts(_, info):
    """Return all published posts."""
    return [post for post in POSTS_DB.values() if post["published"]]


