@post_type.field("author")
def resolve_post_author(post, info):
    """Resolve the author User from the post's author_id."""
    author_id = post.get("author_id")
    if author_id:
        return USERS_DB.get(author_id)
    return None


# --- Build Schema ---

schema = make_executable_schema(
    type_defs,
    query,
    user_type,
    post_type,
    snake_case_fallback_resolvers,
)

